(410, 8, 'true_false', 'Georgia O\'Keeffe\'s style was greatly influenced by the changing fashions in art over the seven decades of her career.', NULL, 'FALSE', NULL, NULL, 1, '"studying at the Art Institute of Chicago."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(410, 9, 'true_false', 'When O\'Keeffe finished high school, she had already made her mind up about the career that she wanted.', NULL, 'TRUE', NULL, NULL, 1, '"a relationship began that would shape both of their lives — they later married."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(410, 10, 'true_false', 'Alfred Stieglitz first discovered O\'Keeffe\'s work when she sent some abstract drawings to his gallery in New York City.', NULL, 'FALSE', NULL, NULL, 1, 'The text describes them as "unlike anything seen before" without stating immediate popularity.', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(410, 11, 'true_false', 'O\'Keeffe was the subject of Stieglitz\'s photographic work for many years.', NULL, 'TRUE', NULL, NULL, 1, '"She spent her final years in Santa Fe, New Mexico."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(410, 12, 'true_false', 'O\'Keeffe\'s paintings of the patio of her house in Abiquiú were among the artist\'s favourite works.', NULL, 'NOT GIVEN', NULL, NULL, 1, '"she continued to create art with the help of assistants."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(410, 13, 'true_false', 'O\'Keeffe produced a greater quantity of work during the 1950s to 1970s than at any other time in her life.', NULL, 'NOT GIVEN', NULL, NULL, 1, 'No mention of learning from other artists in New Mexico.', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 14, 'matching', 'how a type of plant functions as a natural protection for coastlines', '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'C', NULL, NULL, 1, 'Para C explains mangrove roots trap sediment and dampen waves.', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 15, 'matching', 'a prediction about how long it could take to stop noticing the effects of climate change', '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'A', NULL, NULL, 1, '"global warming would continue for around 40 years."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 16, 'matching', 'a reference to the fact that a solution is particularly cost-effective', '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'D', NULL, NULL, 1, '"about a third of what it would cost to completely replace a building\'s foundations."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 17, 'matching', 'a mention of a technology used to locate areas most in need of intervention', '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'F', NULL, NULL, 1, '"Using a Geographic Information System data mapping tool."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 18, 'fill_blank', 'But scientific studies suggest that procrastination is actually due to poor mood management. The tasks we are most likely to put off are those that could damage our self-esteem or cause us to feel ______ when we think about them. Research comparing chronic procrastinators with other people even found differences in the brain regions associated with regulating emotions and identifying ______.', NULL, 'pumps', NULL, NULL, 1, '"set up new pumps that can remove up to 75,000 litres of water per minute."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 19, 'fill_blank', 'But scientific studies suggest that procrastination is actually due to poor mood management. The tasks we are most likely to put off are those that could damage our self-esteem or cause us to feel ______ when we think about them. Research comparing chronic procrastinators with other people even found differences in the brain regions associated with regulating emotions and identifying ______.', NULL, 'dams', NULL, NULL, 1, '"building semi-permeable dams, made from bamboo poles and brushwood."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 20, 'fill_blank', 'Emotionally loaded and difficult tasks often cause us to procrastinate. Getting ready to take ______ might be a typical example of one such task.', NULL, 'float', NULL, NULL, 1, '"these ones had been built to float."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 21, 'fill_blank', 'People who are likely to procrastinate tend to be either ______ or those with low self-esteem.', NULL, 'crops', NULL, NULL, 1, '"start cultivating naturally salt-tolerant crops."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 22, 'fill_blank', 'Procrastination is only a short-term measure for managing emotions. It\'s often followed by a feeling of ______, which worsens our mood and leads to more procrastination.', NULL, 'trees', NULL, NULL, 1, '"include the planting of trees."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 23, 'matching', 'It is essential to adopt strategies which involve and help residents of the region.', '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'seemed to find the activity calming', NULL, NULL, 1, 'Tol: "critical that we transition towards multifunctional approaches."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 24, 'matching', 'Interventions which reduce heat are absolutely vital for our survival in this location.', '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'demonstrated independence', NULL, NULL, 1, '"Urban cooling is literally a matter of life and death for our future in LA."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 25, 'matching', 'More work will need to be done in future decades to deal with the impact of rising water levels.', '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'developed a competitive attitude', NULL, NULL, 1, '"We know that in 20, 30, 40 years, we\'ll need to go back."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(420, 26, 'matching', 'The number of locations requiring action to adapt to flooding has grown in recent years.', '["demonstrated independence","asked for teacher support","developed a competitive attitude","seemed to find the activity calming","seemed pleased with the results","seemed confused","seemed to find the activity easy"]', 'seemed to find the activity easy', NULL, NULL, 1, '"this technology is becoming necessary in places that didn\'t previously need it."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(430, 27, 'matching', 'an example of how one predator has been protected by the introduction of livestock guard dogs', '["A","B","C","D","E","F"]', 'C', NULL, NULL, 1, '"the use of guard dogs in Namibia, where they are used to protect cattle from cheetahs."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(430, 28, 'matching', 'an optimistic suggestion about the possible positive developments in the use of livestock guard dogs', '["A","B","C","D","E","F"]', 'F', NULL, NULL, 1, '"many conservationists see a bright future for guard dogs."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(430, 29, 'matching', 'a description of how the methods used by livestock guard dogs help to keep predators away', '["A","B","C","D","E","F"]', 'A', NULL, NULL, 1, '"placing themselves between the livestock and any perceived threat."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(430, 30, 'matching', 'claims by different academics that the use of livestock guard dogs is a successful way of protecting farmers\' herds', '["A","B","C","D","E","F"]', 'E', NULL, NULL, 1, 'Ribeiro: ~90% reduction; Van Bommel/Johnson: 65% reduction.', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(430, 31, 'matching', 'a reference to how livestock guard dogs gain their skills', '["A","B","C","D","E","F"]', 'B', NULL, NULL, 1, '"raised from an early age with the animals they are meant to protect."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(430, 32, 'matching', 'The use of guard dogs may save the lives of both livestock and wild animals.', '["A","B","C","D","E","F"]', 'Julie Young', NULL, NULL, 1, '"a \'win-win\' situation that saves both livestock and wild animals."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(430, 33, 'matching', 'Claims of a change in behaviour from those using livestock guard dogs may not be totally accurate.', '["A","B","C","D","E","F"]', 'Bethany Smith', NULL, NULL, 1, '"should be \'taken with a pinch of salt\' because data comes from farmers."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(430, 34, 'matching', 'There may be negative results if the use of livestock guard dogs is not sufficiently widespread.', '["A","B","C","D","E","F"]', 'Silvia Ribeiro', NULL, NULL, 1, '"wolf pressure is simply transferred to neighbouring farms."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(430, 35, 'matching', 'Livestock guard dogs are the best way of protecting farm animals, as long as the dogs are appropriately handled.', '["A","B","C","D","E","F"]', 'Linda van Bommel', NULL, NULL, 1, '"the most efficient control method for protecting livestock from predators."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(430, 36, 'matching', 'Teaching a livestock guard dog how to do its work needs a different focus from teaching a house guard dog.', '["A","B","C","D","E","F"]', 'Dan Macon', NULL, NULL, 1, '"a different focus compared to house guard dogs."', NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
