INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20012, 11, 'multiple_choice', 'Heather says pottery differs from other art forms because', '["A. it lasts longer in the ground.","B. it is practised by more people.","C. it can be repaired more easily."]', 'A. it lasts longer in the ground.', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20012, 12, 'multiple_choice', 'Archaeologists sometimes identify the use of ancient pottery from', '["A. the clay it was made with.","B. the marks that are on it.","C. the basic shape of it."]', 'B. the marks that are on it.', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20012, 13, 'multiple_choice', 'Some people join Heather\'s pottery class because they want to', '["A. create an item that looks very old.","B. find something that they are good at.","C. make something that will outlive them."]', 'C. make something that will outlive them.', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20012, 14, 'multiple_choice', 'What does Heather value most about being a potter?', '["A. its calming effect","B. its messy nature","C. its physical benefits"]', 'A. its calming effect', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20012, 15, 'multiple_choice', 'Most of the visitors to Edelman Pottery', '["A. bring friends to join courses.","B. have never made a pot before.","C. try to learn techniques too quickly."]', 'B. have never made a pot before.', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20012, 16, 'multiple_choice', 'Heather reminds her visitors that they should', '["A. put on their aprons.","B. change their clothes.","C. take off their jewellery."]', 'C. take off their jewellery.', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20012, 17, 'multiple_choice', 'Which ** TWO ** things does Heather explain about kilns?', '["A. what their function is","B. when they were invented","C. ways of keeping them safe","D. where to put one in your home","E. what some people use instead of one"]', 'A. what their function is', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20012, 18, 'multiple_choice', 'Which TWO things does Heather explain about kilns? (second)', '["A. what their function is","B. when they were invented","C. ways of keeping them safe","D. where to put one in your home","E. what some people use instead of one"]', 'E. what some people use instead of one', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20012, 19, 'multiple_choice', 'Which ** TWO ** points does Heather make about a potter\'s tools?', '["A. Some are hard to hold.","B. Some are worth buying.","C. Some are essential items.","D. Some have memorable names.","E. Some are available for use by participants."]', 'C. Some are essential items.', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20012, 20, 'multiple_choice', 'Which TWO points does Heather make about a potters tools? (second)', '["A. Some are hard to hold.","B. Some are worth buying.","C. Some are essential items.","D. Some have memorable names.","E. Some are available for use by participants."]', 'E. Some are available for use by participants.', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20013, 21, 'multiple_choice', 'Which ** TWO ** things do the students both believe are responsible for the increase in loneliness?', '["A. social media","B. smaller nuclear families","C. urban design","D. longer lifespans","E. a mobile workforce"]', 'C. urban design', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20013, 22, 'multiple_choice', '(second answer)', '["A. social media","B. smaller nuclear families","C. urban design","D. longer lifespans","E. a mobile workforce"]', 'E. a mobile workforce', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20013, 23, 'multiple_choice', 'Which ** TWO ** health risks associated with loneliness do the students agree are based on solid evidence?', '["A. a weakened immune system","B. dementia","C. cancer","D. obesity","E. cardiovascular disease"]', 'A. a weakened immune system', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20013, 24, 'multiple_choice', '(second answer)', '["A. a weakened immune system","B. dementia","C. cancer","D. obesity","E. cardiovascular disease"]', 'C. cancer', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20013, 25, 'multiple_choice', 'Which ** TWO ** opinions do both the students express about the evolutionary theory of loneliness?', '["A. It has little practical relevance.","B. It needs further investigation.","C. It is misleading.","D. It should be more widely accepted.","E. It is difficult to understand."]', 'A. It has little practical relevance.', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20013, 26, 'multiple_choice', '(second answer)', '["A. It has little practical relevance.","B. It needs further investigation.","C. It is misleading.","D. It should be more widely accepted.","E. It is difficult to understand."]', 'B. It needs further investigation.', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20013, 27, 'multiple_choice', 'When comparing loneliness to depression, the students', '["A. doubt that there will ever be a medical cure for loneliness.","B. claim that the link between loneliness and mental health is overstated.","C. express frustration that loneliness is not taken more seriously."]', 'A. doubt that there will ever be a medical cure for loneliness.', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20013, 28, 'multiple_choice', 'Why do the students decide to start their presentation with an example from their  own experience?', '["A. to explain how difficult loneliness can be","B. to highlight a situation that most students will recognise","C. to emphasise that feeling lonely is more common for men than women"]', 'B. to highlight a situation that most students will recognise', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20013, 29, 'multiple_choice', 'The students agree that talking to strangers is a good strategy for dealing with loneliness because', '["A. it creates a sense of belonging.","B. it builds self-confidence.","C. it makes people feel more positive."]', 'A. it creates a sense of belonging.', NULL, NULL, 1, NULL, NOW());
INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
