INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(20014, 31, 'fill_blank', NULL, NULL, 'factories', NULL, '[note]\n# Reclaiming urban rivers\n## Historical background\n● Nearly all major cities were built on a river.\n● Rivers were traditionally used by city dwellers for transport, fishing and recreation.\n● Industrial development and rising populations later led to:\n○ more sewage from houses being discharged into the river\n○ pollution from {Q31} on the river bank.\n● In 1957, the River Thames in London was declared biologically {Q32} .\n## Recent improvements\n● Seals and even a {Q33} have been seen in the River Thames.\n● Riverside warehouses are converted to restaurants and {Q34}\n● In Los Angeles, there are plans to:\n○ build a riverside {Q35}\n○ display {Q36} projects.\n● In Paris, {Q37} are created on the sides of the river every summer.\n## Transport possibilities\n● Over 2 billion passengers already travel by {Q38} in cities round the world.\n● Changes in shopping habits mean the number of deliveries that are made is increasing.\n● Instead of road transport, goods could be transported by large freight barges and electric {Q39} or, in future, by {Q40} .', 1, NULL, NOW());
